class Solution:
    def alternatingSubarray(self, nums):
        n = len(nums)
        best = -1
        for l in range(n):
            for r in range(l + 1, n):
                ok = True
                for k in range(l, r):
                    want = 1 if (k - l) % 2 == 0 else -1
                    if nums[k + 1] - nums[k] != want:
                        ok = False
                        break
                if ok:
                    best = max(best, r - l + 1)
        return best

