class Solution:
    def alternatingSubarray(self, nums):
        n = len(nums)
        best = -1
        i = 0
        while i < n - 1:
            if nums[i + 1] - nums[i] == 1:
                j = i + 1
                expected = -1
                while j + 1 < n and nums[j + 1] - nums[j] == expected:
                    expected = -expected
                    j += 1
                best = max(best, j - i + 1)
            i += 1
        return best

