var alternatingSubarray = function(nums) {
    const n = nums.length;
    let best = -1;
    let i = 0;
    while (i < n - 1) {
        if (nums[i + 1] - nums[i] === 1) {
            let j = i + 1;
            let expected = -1;
            while (j + 1 < n && nums[j + 1] - nums[j] === expected) {
                expected = -expected;
                j++;
            }
            best = Math.max(best, j - i + 1);
        }
        i++;
    }
    return best;
};
